// Consolidate v2: consulta buffer compartido del RAG server
const input = $input.first().json;
const phone = input.telefono;
const my_ts = input._my_ts;

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:3003/api/buffer/consume',
    headers: { 'Content-Type': 'application/json' },
    body: { phone, my_ts },
    json: true,
  });
} catch (err) {
  // Si el buffer service esta caido, procesamos como single msg (no batching)
  console.log('[consolidate] buffer/consume error:', err.message);
  return [{ json: input }];
}

if (resp && resp.skip === true) {
  // No soy el ultimo o buffer vacio → skip silencioso
  return [];
}

// Soy el ultimo y consolide. Si el texto consolidado tiene mas que mi texto,
// pisar el mensaje_original con el consolidado.
const consolidatedText = resp && resp.consolidated_text;
const count = (resp && resp.count) || 1;

return [{
  json: {
    ...input,
    mensaje_original: (input.msg_type === 'text' && consolidatedText) ? consolidatedText : input.mensaje_original,
    _consolidated_count: count,
    _consolidated_msgs: (resp && resp.msgs) || []
  }
}];

// Filtra conversaciones de este cliente y formatea historial.
// Es tolerante: si no hay datos, devuelve placeholder limpio.
let telefono = "";
try { telefono = String($("Merge Caminos").first().json.telefono || ""); } catch(e) {}

let allRows = [];
try { allRows = $input.all().map(i => i.json); } catch(e) {}

const rows = allRows.filter(r => String(r.telefono || "") === telefono);

if (rows.length === 0) {
  return [{ json: { historial: "(sin historial previo, este es el primer contacto)" } }];
}

rows.sort((a,b) => String(a.timestamp || "").localeCompare(String(b.timestamp || "")));
const recientes = rows.slice(-20);

const lineas = recientes.map(f => {
  const who = String(f.direccion || "in") === "in" ? "Cliente" : "Cami";
  const msg = String(f.mensaje || "").replace(/\n/g, " ").slice(0, 300);
  const ts = String(f.timestamp || "").slice(0, 19).replace("T", " ");
  return "[" + ts + "] " + who + ": " + msg;
});

return [{ json: { historial: lineas.join("\n") } }];

// Match CLIP con score HIBRIDO (visual + texto) y filter por ambiente.
// Thresholds nuevos: 0.80 confirma, 0.65 posible match.
const inp = $input.first().json || {};
const items = Array.isArray(inp.items) ? inp.items : [];
const top = items[0] || null;
const incomingAmbient = inp.incoming_ambient || 'detalle';
const incomingDesc = inp.incoming_desc || '';

const parserData = $("Parsear Mensaje").first().json || {};
const caption = parserData.mensaje_original || "";

function detallesProp(p) {
  if (!p) return "";
  const parts = [];
  if (p.title) parts.push("Titulo: " + p.title);
  if (p.address || p.barrio || p.zona) parts.push("Ubicacion: " + [p.address, p.barrio, p.zona].filter(Boolean).join(", "));
  if (p.operation) parts.push("Operacion: " + (p.operation === "sale" ? "venta" : p.operation === "rent" ? "alquiler" : p.operation));
  if (p.property_type) parts.push("Tipo: " + p.property_type);
  if (p.bedrooms !== null && p.bedrooms !== undefined) parts.push("Ambientes: " + p.bedrooms);
  if (p.bathrooms !== null && p.bathrooms !== undefined) parts.push("Banos: " + p.bathrooms);
  if (p.area_m2) parts.push("Superficie: " + p.area_m2 + " m2");
  if (p.price) parts.push("Precio: " + p.price + " " + (p.price_currency || ""));
  else if (p.price_text) parts.push("Precio: " + p.price_text);
  if (p.features && p.features.length) parts.push("Caracteristicas: " + p.features.join(", "));
  if (p.url) parts.push("URL: " + p.url);
  return parts.join(" | ");
}

let clipBlock = "[SIN_MATCH_VISUAL] No hay similitud visual clara con el catalogo. Pedile al cliente la direccion o el ID de la propiedad para confirmar.";

if (top) {
  const sc = Number(top.score || 0);
  const clipS = Number(top.clip_score || 0);
  const textS = Number(top.text_score || 0);
  const scoresInfo = "hybrid=" + sc.toFixed(3) + " (clip=" + clipS.toFixed(3) + ", text=" + textS.toFixed(3) + ")";

  if (sc >= 0.80) {
    clipBlock = "[CONFIRMADO_VISUAL] " + scoresInfo + "\n" +
      "Identifique con alta confianza esta propiedad (ambiente detectado: " + incomingAmbient + "):\n" + detallesProp(top) + "\n\n" +
      "INSTRUCCION: Habla de ESTA propiedad con confianza. NO le pidas la direccion al cliente. Usa todos los detalles (ambientes, m2, precio, ubicacion, caracteristicas) para charlar a fondo y ofrecer agendar visita.";
  } else if (sc >= 0.65) {
    let alts = items.slice(1, 3).map((p, i) => "  " + (i+2) + ") " + (p.title || "?") + " (hybrid=" + Number(p.score || 0).toFixed(3) + ") | " + (p.address || p.barrio || "?")).join("\n");
    clipBlock = "[POSIBLE_MATCH] " + scoresInfo + "\n" +
      "Candidato mas probable (ambiente: " + incomingAmbient + "):\n" + detallesProp(top) + "\n" +
      (alts ? "Otras posibles:\n" + alts + "\n" : "") +
      "\nINSTRUCCION: Mencionale al cliente que esta foto se PARECE a [propiedad de arriba] y preguntale si es esa. Si confirma, hablar a detalle. Si no, pedir direccion.";
  } else if (items.length > 0) {
    const tops = items.slice(0, 3).map((p, i) => (i+1) + ") " + (p.title || "?") + " hybrid=" + Number(p.score || 0).toFixed(3) + " | " + (p.address || p.barrio || p.zona || "?")).join(" || ");
    clipBlock = "[MATCH_DEBIL] Ningun candidato con alta confianza. " + scoresInfo + ". Top 3 mas parecidos:\n" + tops + "\n\nINSTRUCCION: Pedile al cliente que confirme la direccion o el ID de la propiedad.";
  }
}

const captionBlock = caption ? ("\n\n[CAPTION DEL CLIENTE] " + caption) : "";
const descBlock = incomingDesc ? ("\n\n[VISION DESC] " + incomingDesc) : "";
const mensaje = "[IMAGEN RECIBIDA - ambiente=" + incomingAmbient + "]" + descBlock + "\n\n" + clipBlock + captionBlock;

return [{ json: Object.assign({}, parserData, { mensaje: mensaje }) }];

// Calendario laboral REAL: feriados + vacaciones + horarios custom + capacity
const TZ = 'America/Argentina/Buenos_Aires';
const DIAS_MAP = { 0: 'D', 1: 'L', 2: 'M', 3: 'X', 4: 'J', 5: 'V', 6: 'S' };
const DIAS_NOMBRE = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const MESES = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

const nowARG = new Date(new Date().toLocaleString('en-US', { timeZone: TZ }));
function fmtFecha(d) { return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'); }
function fmtFechaLarga(d) { return DIAS_NOMBRE[d.getDay()] + ' ' + d.getDate() + ' de ' + MESES[d.getMonth()] + ' de ' + d.getFullYear(); }
function fmtHora(d) { return String(d.getHours()).padStart(2,'0') + ':' + String(d.getMinutes()).padStart(2,'0'); }

const hoy = nowARG;
const en7 = new Date(hoy); en7.setDate(hoy.getDate()+7);

// CONTEXTO TEMPORAL (igual que antes)
function proximoDia(diaSemana) {
  const d = new Date(hoy);
  const diff = (diaSemana - d.getDay() + 7) % 7 || 7;
  d.setDate(d.getDate() + diff);
  return d;
}
const contextoTemporal = "" +
  "HOY es: " + fmtFechaLarga(hoy) + " | ISO: " + fmtFecha(hoy) + "\n" +
  "Hora actual Bahia Blanca: " + fmtHora(hoy) + " (Argentina, GMT-3)\n" +
  "MANANA: " + fmtFechaLarga(proximoDia((hoy.getDay()+1)%7)) + "\n" +
  "Lunes proximo: " + fmtFecha(proximoDia(1)) + " | Martes: " + fmtFecha(proximoDia(2)) +
  " | Miercoles: " + fmtFecha(proximoDia(3)) + " | Jueves: " + fmtFecha(proximoDia(4)) +
  " | Viernes: " + fmtFecha(proximoDia(5)) + " | Sabado: " + fmtFecha(proximoDia(6)) + "\n\n" +
  "REGLA: JAMAS uses fechas antes de " + fmtFecha(hoy) + ". JAMAS mas alla de 30 dias.";

// Cargar data
let empleados = [];
let visitas = [];
let feriados = [];
try { empleados = $("Cargar Empleados Activos").all().map(i => i.json); } catch(e) {}
try { visitas = $("Cargar Visitas Proximas").all().map(i => i.json); } catch(e) {}
try { feriados = $("Cargar Feriados").all().map(i => i.json); } catch(e) {}

const feriadosSet = new Set(feriados.map(f => String(f.fecha || '').trim()));

// Filtrar empleados activos no en vacaciones HOY
const activos = empleados.filter(e => {
  const isActivo = String(e.activo).toLowerCase() === 'true' || e.activo === true;
  if (!isActivo) return false;
  return true;
});

// Para cada activo, marcar si esta en vacaciones HOY
function enVacacionesEn(emp, fecha) {
  const vd = emp.vacacion_desde;
  const vh = emp.vacacion_hasta;
  if (!vd || !vh) return false;
  const f = fecha;
  return f >= String(vd).trim() && f <= String(vh).trim();
}

// Bloque EQUIPO con status
let equipoBlock;
if (activos.length === 0) {
  equipoBlock = '(sin vendedores activos)';
} else {
  equipoBlock = activos.map(e => {
    const enVac = enVacacionesEn(e, fmtFecha(hoy));
    const status = enVac ? ' [EN VACACIONES hasta ' + e.vacacion_hasta + ']' : '';
    return '  - ' + (e.nombre || '?') + ' (id=' + (e.empleado_id || '?') + ', tel=' + (e.telefono || '?') + ', zonas=' + (e.zona_especialidad || 'todas') + ', horario=' + (e.horario_inicio || '09:00') + '-' + (e.horario_fin || '19:00') + ')' + status;
  }).join('\n');
}

// Visitas proximas 7 dias para calcular ocupacion
function parseFecha(f) {
  if (!f) return null;
  if (typeof f === 'number' || /^\d+(\.\d+)?$/.test(String(f))) {
    const days = Number(f);
    if (days < 1000) return null;
    return new Date((days - 25569) * 86400 * 1000);
  }
  const d = new Date(String(f));
  return isNaN(d.getTime()) ? null : d;
}
const proximas = visitas.filter(v => {
  const fd = parseFecha(v.fecha);
  if (!fd) return false;
  return fd >= new Date(hoy.getFullYear(), hoy.getMonth(), hoy.getDate()) && fd <= en7 && String(v.estado || '').toLowerCase() !== 'cancelada';
});

// AGENDA OCUPADA por vendedor
const ocupadasPorVendedor = {};
for (const v of proximas) {
  const vid = v.vendedor_id || v.vendedor_nombre || '?';
  if (!ocupadasPorVendedor[vid]) ocupadasPorVendedor[vid] = [];
  const fd = parseFecha(v.fecha);
  ocupadasPorVendedor[vid].push({ fecha: fmtFecha(fd), hora: v.hora || '?', cliente: v.cliente_nombre || '?', direccion: v.direccion || '?' });
}

let agendaOcupadaBlock = '(sin visitas agendadas)';
if (proximas.length > 0) {
  proximas.sort((a,b) => {
    const da = parseFecha(a.fecha) || new Date(0);
    const db = parseFecha(b.fecha) || new Date(0);
    return da - db;
  });
  agendaOcupadaBlock = proximas.map(v => {
    const fd = parseFecha(v.fecha);
    return '  - ' + fmtFecha(fd) + ' ' + (v.hora || '?') + ' | ' + (v.vendedor_nombre || '?') + ' visita a ' + (v.cliente_nombre || '?') + ' en ' + (v.direccion || '?');
  }).join('\n');
}

// SLOTS DISPONIBLES por vendedor proximos 7 dias
// Genera horarios cada 1.5h dentro del horario laboral, excluye feriados, dias no laborales, vacaciones, y slots ocupados
function generarSlots(emp, fechaStr, fechaDate, ocupados) {
  const horaIni = String(emp.horario_inicio || '09:00');
  const horaFin = String(emp.horario_fin || '19:00');
  const [hi, mi] = horaIni.split(':').map(Number);
  const [hf, mf] = horaFin.split(':').map(Number);
  const slots = [];
  let h = hi, m = mi;
  while (h < hf || (h === hf && m === 0)) {
    if (h >= hi && (h < hf || (h === hf && m === 0))) {
      const slotHora = String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0');
      const ocupadoEnEsteSlot = ocupados.some(o => o.fecha === fechaStr && o.hora === slotHora);
      if (!ocupadoEnEsteSlot) slots.push(slotHora);
    }
    m += 90;
    while (m >= 60) { h += 1; m -= 60; }
  }
  return slots;
}

let disponibilidadBlock = '';
for (const emp of activos) {
  if (enVacacionesEn(emp, fmtFecha(hoy))) {
    disponibilidadBlock += '\n' + (emp.nombre || '?') + ': EN VACACIONES hasta ' + emp.vacacion_hasta + ' (no agendar)';
    continue;
  }
  const diasLaborales = String(emp.dias_laborales || 'L,M,X,J,V,S').split(',').map(d => d.trim());
  const maxPorDia = parseInt(emp.max_visitas_dia || '4', 10);
  const empOcupados = ocupadasPorVendedor[emp.empleado_id] || [];

  const slotsPorDia = [];
  for (let i = 1; i <= 7; i++) {
    const d = new Date(hoy); d.setDate(hoy.getDate() + i);
    const fechaStr = fmtFecha(d);
    if (feriadosSet.has(fechaStr)) continue;
    const diaCorto = DIAS_MAP[d.getDay()];
    if (!diasLaborales.includes(diaCorto)) continue;
    if (enVacacionesEn(emp, fechaStr)) continue;
    const ocupadosEnDia = empOcupados.filter(o => o.fecha === fechaStr).length;
    if (ocupadosEnDia >= maxPorDia) continue;
    const slots = generarSlots(emp, fechaStr, d, empOcupados).slice(0, maxPorDia - ocupadosEnDia);
    if (slots.length > 0) {
      slotsPorDia.push(fechaStr + ' (' + DIAS_NOMBRE[d.getDay()] + '): ' + slots.join(', '));
    }
  }
  if (slotsPorDia.length === 0) {
    disponibilidadBlock += '\n' + (emp.nombre || '?') + ' (' + (emp.zona_especialidad || 'todas') + '): SIN SLOTS DISPONIBLES en los proximos 7 dias';
  } else {
    disponibilidadBlock += '\n' + (emp.nombre || '?') + ' (' + (emp.zona_especialidad || 'todas') + '):\n  ' + slotsPorDia.join('\n  ');
  }
}

// FERIADOS proximos
const feriadosProx = feriados.filter(f => {
  const fd = String(f.fecha || '').trim();
  return fd >= fmtFecha(hoy) && fd <= fmtFecha(en7);
});
const feriadosBlock = feriadosProx.length === 0
  ? '(ningun feriado en los proximos 7 dias)'
  : feriadosProx.map(f => '  - ' + f.fecha + ' ' + (f.nombre || '')).join('\n');

const equipoYAgenda = '## EQUIPO ACTIVO\n' + equipoBlock +
  '\n\n## FERIADOS PROXIMOS 7 DIAS (no agendar)\n' + feriadosBlock +
  '\n\n## AGENDA YA OCUPADA (no proponer estos slots)\n' + agendaOcupadaBlock +
  '\n\n## SLOTS DISPONIBLES PROXIMOS 7 DIAS POR VENDEDOR\n' + disponibilidadBlock +
  '\n\n## REGLAS\n' +
  '- JAMAS propongas un slot que NO este en SLOTS DISPONIBLES arriba.\n' +
  '- Si el cliente pide algo fuera de la lista, decile que no hay disponibilidad y ofrecele alternativas reales.\n' +
  '- Asigna el vendedor segun zona de la propiedad (si zona coincide con zona_especialidad).';

const base = $input.first().json || {};
return [{ json: Object.assign({}, base, { contextoTemporal, equipoYAgenda }) }];

// Lee estado del lead (bot_pausado_hasta, conversacion_cerrada) y decide si seguir.
const lead = $input.first().json || {};
const mensaje = String(($("Merge Caminos").first().json.mensaje || $("Merge Caminos").first().json.mensaje_original || "")).toLowerCase().trim();
const ahora = new Date();

// Check pausa por humano
const pausadoHasta = lead.bot_pausado_hasta;
if (pausadoHasta) {
  const fp = new Date(pausadoHasta);
  if (!isNaN(fp.getTime()) && fp > ahora) {
    return [{ json: { skip: true, reason: "bot_pausado_por_humano", pausado_hasta: pausadoHasta } }];
  }
}

// Check conversacion cerrada (si lo esta, solo reactivar si el cliente saluda nuevo)
const cerrada = String(lead.conversacion_cerrada || "").toLowerCase() === "true";
if (cerrada) {
  const esSaludoNuevo = /^(hola|buen[oa]s|qué tal|hi |hey |holi)/i.test(mensaje);
  if (!esSaludoNuevo) {
    return [{ json: { skip: true, reason: "conversacion_cerrada_sin_saludo" } }];
  }
  // Es saludo: continuar (el flujo despues va a re-activar via Admin)
}

// Bot activo, continuar. Propagar campos del Merge Caminos para los nodos siguientes.
const merge = $("Merge Caminos").first().json || {};
return [{ json: Object.assign({}, merge, { skip: false, reason: "bot_activo" }) }];

// Parser v8: HMAC validation (modo WARN) + handoff + buffer
const crypto = require('crypto');
const raw = $input.first().json;
const body = raw.body || raw;
const headers = raw.headers || {};

// HMAC validation (WARN mode - solo loggea)
const HMAC_SECRET = 'n1Jxiri0SdH9CC3a66x2m3ot32pAiJTS8iLAmO6iHIQ=';
const receivedSig = String(headers['x-webhook-signature'] || '');
let sigOk = false;
let sigMode = 'no_header';
if (receivedSig) {
  try {
    // Probar distintos formatos para encontrar el correcto
    const bodyStr = JSON.stringify(body);
    const h1 = crypto.createHmac('sha256', HMAC_SECRET).update(bodyStr).digest('base64');
    const h2 = crypto.createHmac('sha256', Buffer.from(HMAC_SECRET, 'base64')).update(bodyStr).digest('base64');
    if (h1 === receivedSig) { sigOk = true; sigMode = 'sha256_secret_string'; }
    else if (h2 === receivedSig) { sigOk = true; sigMode = 'sha256_secret_b64decoded'; }
    else { sigMode = 'mismatch_h1=' + h1.slice(0,12) + '_h2=' + h2.slice(0,12) + '_recv=' + receivedSig.slice(0,12); }
  } catch (e) { sigMode = 'error_' + e.message.slice(0,50); }
}
console.log('[HMAC]', sigMode, '| receivedSig=' + receivedSig.slice(0,20));

const isRespondio = !!(body.event_type || body.contact || body.message);
let from = '';
let profile = 'Desconocido';
let text_body = '';
let media_url = '';
let media_type = '';
let msg_type = 'text';
let canal = 'whatsapp';
let contact_id_val = null;
let evento = '';
let es_humano = false;
let es_bot_propio = false;

if (isRespondio) {
  const contact = body.contact || {};
  contact_id_val = contact.id || null;
  const outerMessage = body.message || {};
  const innerMessage = outerMessage.message || outerMessage;
  const attachment = innerMessage.attachment || null;
  const sender = body.sender || {};
  evento = String(body.event_type || '');

  from = String(contact.phone || '').replace(/^\+/, '');
  profile = (contact.firstName || '') + (contact.lastName ? ' ' + contact.lastName : '');
  profile = profile.trim() || 'Desconocido';
  canal = 'whatsapp_respondio';

  if (evento === 'message.sent' || evento === 'message_sent') {
    const src = String(sender.source || '').toLowerCase();
    if (src === 'user' || src === 'agent' || (sender.userId && src !== 'bot' && src !== 'api')) {
      es_humano = true;
    } else {
      es_bot_propio = true;
    }
  }

  let effectiveType = String(innerMessage.type || 'text').toLowerCase();
  if (effectiveType === 'attachment' && attachment) {
    effectiveType = String(attachment.type || '').toLowerCase();
    if (!effectiveType && attachment.mimeType) {
      const mt = String(attachment.mimeType).toLowerCase();
      if (mt.startsWith('audio/')) effectiveType = 'audio';
      else if (mt.startsWith('image/')) effectiveType = 'image';
      else if (mt.startsWith('video/')) effectiveType = 'video';
      else effectiveType = 'document';
    }
  }

  if (effectiveType === 'text') {
    text_body = String(innerMessage.text || innerMessage.body || '');
    msg_type = 'text';
  } else if (effectiveType === 'image') {
    msg_type = 'image';
    media_url = String((attachment && attachment.url) || innerMessage.url || '');
    media_type = String((attachment && attachment.mimeType) || 'image/jpeg').split(';')[0];
    text_body = String(innerMessage.text || innerMessage.caption || (attachment && attachment.caption) || '');
  } else if (effectiveType === 'audio' || effectiveType === 'voice') {
    msg_type = 'audio';
    media_url = String((attachment && attachment.url) || innerMessage.url || '');
    media_type = String((attachment && attachment.mimeType) || 'audio/ogg').split(';')[0];
    text_body = '';
  } else if (effectiveType === 'video') {
    msg_type = 'document';
    media_url = String((attachment && attachment.url) || innerMessage.url || '');
    media_type = String((attachment && attachment.mimeType) || 'video/mp4').split(';')[0];
    text_body = String(innerMessage.text || '[video recibido]');
  } else {
    msg_type = 'document';
    media_url = String((attachment && attachment.url) || innerMessage.url || '');
    media_type = String((attachment && attachment.mimeType) || 'application/octet-stream').split(';')[0];
    text_body = String(innerMessage.text || innerMessage.body || '[adjunto recibido]');
  }
} else {
  const from_raw = body.From || body.from || '';
  from = from_raw.replace('whatsapp:', '').replace(/^\+/, '');
  profile = body.ProfileName || body.profileName || 'Desconocido';
  text_body = body.Body || body.body || '';
  canal = 'whatsapp_twilio';
}

if (!from) { return [{ json: { skip: true, reason: 'sin_from', sig_mode: sigMode } }]; }
if (es_bot_propio) { return [{ json: { skip: true, reason: 'bot_propio_no_procesar', sig_mode: sigMode } }]; }
if (es_humano) {
  const digits = from.replace(/\D/g, '');
  return [{ json: { skip: true, reason: 'humano_respondio', mark_pausa: true, telefono: from, contact_id: contact_id_val, lead_id: 'L-' + digits.slice(-10), msg_humano: text_body.slice(0, 200), sig_mode: sigMode } }];
}
if (!text_body && !media_url) { return [{ json: { skip: true, reason: 'payload_invalido', sig_mode: sigMode } }]; }

const cmid = (body.message && body.message.channelMessageId) || ('GEN-' + Date.now() + '-' + Math.random().toString(36).slice(2,8));
const digits_only = from.replace(/\D/g, '');
const my_ts = Date.now();

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:3003/api/buffer/add',
    headers: { 'Content-Type': 'application/json' },
    body: { phone: from, cmid, ts: my_ts, msg_type, text: text_body, media_url, media_type, profile, lead_id: 'L-' + digits_only.slice(-10) },
    json: true,
  });
} catch (err) { console.log('[parser] buffer/add error:', err.message); }

return [{ json: {
  telefono: from, contact_id: contact_id_val, nombre: profile,
  mensaje_original: text_body, msg_type: msg_type, media_url: media_url, media_type: media_type,
  canal: canal, channel_message_id: cmid, lead_id: 'L-' + digits_only.slice(-10),
  msg_id: 'M-' + Date.now(), timestamp_iso: new Date().toISOString(), _my_ts: my_ts,
  skip: false, mark_pausa: false, sig_mode: sigMode
}}];

